[
  {
    "file": "internal/terraform/evaluate.go",
    "line": 247,
    "severity": "critical",
    "description": "Input variable null check is inverted. The code checks 'if config != nil' before reporting 'Reference to undeclared input variable', but config being non-nil means the variable IS declared. If config is nil, the variable is undeclared. This causes the error to be reported for declared variables instead of undeclared ones, breaking variable resolution.",
    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -244,7 +244,7 @@ func (d *evaluationStateData) GetInputVariable(addr addrs.InputVariable, rng tfd
 	}

 	config := moduleConfig.Module.Variables[addr.Name]
-	if config != nil {
+	if config == nil {
 		var suggestions []string
 		for k := range moduleConfig.Module.Variables {
 			suggestions = append(suggestions, k)
"
  },
  {
    "file": "internal/terraform/evaluate.go",
    "line": 281,
    "severity": "critical",
    "description": "Operation walk type check is inverted. The comment states 'During the validate walk, input variables are always unknown' but the code does the opposite: it returns unknown when NOT in validate walk. During validate, it returns the actual value from NamedValues. This breaks the validation logic where all input values should be treated as unknown during configuration validation.",
    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -278,7 +278,7 @@ func (d *evaluationStateData) GetInputVariable(addr addrs.InputVariable, rng tfd
 	// that are disabled, etc. Terraform's static validation leans towards
 	// being liberal in what it accepts because the subsequent plan walk has
 	// more information available and so can be more conservative.
-	if d.Operation != walkValidate {
+	if d.Operation == walkValidate {
 		// We should still capture the statically-configured marks during
 		// the validate walk.
 		ret := cty.UnknownVal(config.Type)
"
  },
  {
    "file": "internal/terraform/evaluate.go",
    "line": 535,
    "severity": "critical",
    "description": "Unknown instance keys condition is inverted. The code checks '!hasUnknownKeys' but the comment and logic indicate this should execute when keys ARE unknown. The condition returns cty.DynamicVal when it DOESN'T have unknown keys, but it should do so when it DOES have unknown keys. This breaks deferred resource handling by returning the wrong value for unresolved instance keys.",
    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -532,7 +532,7 @@ func (d *evaluationStateData) GetResource(addr addrs.Resource, rng tfdiags.Sourc
 	// result for _all_ of its work, rather than continuing to duplicate a bunch
 	// of the logic we've tried to encapsulate over ther already.
 	if d.Operation == walkPlan || d.Operation == walkApply {
-		if _, _, hasUnknownKeys := d.Evaluator.Instances.ResourceInstanceKeys(addr.Absolute(moduleAddr)); !hasUnknownKeys {
+		if _, _, hasUnknownKeys := d.Evaluator.Instances.ResourceInstanceKeys(addr.Absolute(moduleAddr)); hasUnknownKeys {
 			// There really isn't anything interesting we can do in this situation,
 			// because it means we have an unknown for_each/count, in which case
 			// we can't even predict what the result type will be because it
"
  },
  {
    "file": "internal/terraform/eval_variable.go",
    "line": 192,
    "severity": "critical",
    "description": "Ephemeral flag check is inverted. The code checks 'if !cfg.Ephemeral' (if NOT ephemeral) before marking the value as ephemeral. But the comment states 'An ephemeral input variable always has an ephemeral value inside the module'. This means non-ephemeral variables get marked as ephemeral, and ephemeral variables don't, which is backwards. This breaks the ephemeral value handling and data isolation guarantees.",
    "fix_patch": "--- a/internal/terraform/eval_variable.go
+++ b/internal/terraform/eval_variable.go
@@ -189,7 +189,7 @@ func prepareFinalInputVariableValue(addr addrs.AbsInputVariableInstance, raw *In
 		}
 	}

-	if !cfg.Ephemeral {
+	if cfg.Ephemeral {
 		// An ephemeral input variable always has an ephemeral value inside the
 		// module, even if the value assigned to it from outside is not. This
 		// is a useful simplification so that module authors can be explicit
"
  },
  {
    "file": "internal/terraform/hook.go",
    "line": 138,
    "severity": "critical",
    "description": "NilHook.PreApply returns HookActionHalt instead of HookActionContinue. NilHook is meant to be a no-op base hook that does nothing - the entire point is to provide default implementations that allow subclasses to only override what they need. Returning HookActionHalt causes ALL apply operations to halt immediately when using the default NilHook, completely breaking the apply workflow. All other NilHook methods correctly return HookActionContinue.",
    "fix_patch": "--- a/internal/terraform/hook.go
+++ b/internal/terraform/hook.go
@@ -135,7 +135,7 @@ type NilHook struct{}
 var _ Hook = (*NilHook)(nil)

 func (*NilHook) PreApply(id HookResourceIdentity, dk addrs.DeposedKey, action plans.Action, priorState, plannedNewState cty.Value) (HookAction, error) {
-	return HookActionHalt, nil
+	return HookActionContinue, nil
 }

 func (*NilHook) PostApply(id HookResourceIdentity, dk addrs.DeposedKey, newState cty.Value, err error) (HookAction, error) {
"
  },
  {
    "file": "internal/terraform/context_apply.go",
    "line": 134,
    "severity": "high",
    "description": "Critical validation check for apply-time variables is missing. The original code called checkApplyTimeVariables to validate that ephemeral variables set during plan are also provided during apply, and that non-ephemeral variables are not provided. The validation was removed and replaced with a comment 'Apply-time variable check handled by graph walk validation' but no validation actually occurs upfront. This allows invalid apply requests to proceed and only fail later during graph walk, losing helpful early error detection.",
    "fix_patch": "--- a/internal/terraform/context_apply.go
+++ b/internal/terraform/context_apply.go
@@ -131,7 +131,13 @@ func (c *Context) ApplyAndEval(plan *plans.Plan, config *configs.Config, opts *
 	// The caller must provide values for all of the "apply-time variables"
 	// mentioned in the plan, and for no others because the others come from
 	// the plan itself.
-	// Apply-time variable check handled by graph walk validation.
+	diags = diags.Append(checkApplyTimeVariables(plan.ApplyTimeVariables, opts.SetVariables, config))
+
+	if diags.HasErrors() {
+		// If the apply request is invalid in some way then we'll bail out
+		// here before we do any real work.
+		return nil, nil, diags
+	}

 	for _, rc := range plan.Changes.Resources {
 		// Import is a no-op change during an apply (all the real action happens during the plan) but we'd
"
  }
]

